comments.suggestion_code:
# Step a) 查缓存 — 仅当没有 kb 命中时才继续
# 先尝试通过原始文本匹配快速命中缓存（需要向量时再 embed）
query_embedding: list[float] | None = None

for kb_id in kb_ids:
    cached = await self._check_cache(kb_id, query, query_embedding)
    if cached is not None:
        return cached
    # 仅在需要时计算一次 embedding
    if query_embedding is None:
        try:
            vectors = await self.embedder.embed([query])
            query_embedding = vectors[0]
        except Exception:
            pass

